# pylint: disable=all
# type: ignore
import numpy as np
import matplotlib.pyplot as plt
import json, zlib, base64, sys

# Generated by Vectomancy

COMPRESSED_DATA = b""

def _load_data():
    try:
        raw_json = zlib.decompress(base64.b64decode(COMPRESSED_DATA)).decode('utf-8')
        return json.loads(raw_json)
    except Exception as e:
        print(f"Error decoding vector data: {e}", file=sys.stderr)
        sys.exit(1)

def render():
    plt.figure(figsize=(8, 8))
    
    

    
    t_eq = np.linspace(0, 1.0, 50)
    t_eq_powers = np.array([np.ones_like(t_eq), t_eq, t_eq**2, t_eq**3])
    equations_data = _load_data()
    for eq in equations_data:
        x_poly = eq['x_poly']
        y_poly = eq['y_poly']
        x = np.dot(x_poly, t_eq_powers)
        y = np.dot(y_poly, t_eq_powers)
        plt.plot(x, y, 'k-', linewidth=1.0)
    

    

    plt.axis('equal')
    plt.gca().invert_yaxis()
    plt.axis('off')
    
    out_path = sys.argv[1] if len(sys.argv) > 1 else 'render.png'
    plt.savefig(out_path, bbox_inches='tight', dpi=300)

if __name__ == '__main__':
    render()